package com.meltwater.wrapidity.service.groot;

import com.fasterxml.jackson.databind.JsonNode;
import com.fasterxml.jackson.databind.node.ObjectNode;
import com.meltwater.wrapidity.util.misc.JsonUtils;
import org.junit.jupiter.api.Disabled;
import org.junit.jupiter.api.Test;

import java.io.IOException;
import java.net.URI;
import java.net.http.HttpClient;
import java.net.http.HttpRequest;
import java.net.http.HttpResponse;
import java.nio.file.Files;
import java.nio.file.Path;
import java.time.Duration;
import java.util.UUID;

@Disabled
public class SubmitSources {

  private static final String ENDPOINT =
      "https://induction-api-dev-internal.meltwater.io/induction/v2/api/source/submit?force=true";

  /**
   * Extracts the JSON payload from a CSV line.
   * The CSV line has the JSON payload as the last column,
   * enclosed in quotes with escaped quotes inside.
   */
  private static String extractJsonPayload(String csvLine) {
    // Find the last occurrence of "{"
    int lastBraceStart = csvLine.lastIndexOf("\"{");
//    if (lastBraceStart == -1) {
//      throw new IllegalArgumentException("No JSON payload found in CSV line");
//    }

    // Extract from the quote before { to the end
    String quoted = csvLine.substring(lastBraceStart + 1); // Skip the opening quote

    // Remove the trailing quote if present
    if (quoted.endsWith("\"")) {
      quoted = quoted.substring(0, quoted.length() - 1);
    }

    // Unescape double quotes (CSV escaping: "" becomes ")
    return quoted.replace("\"\"", "\"");
  }

  @Test
  void submitRequests() throws Exception {
    HttpClient client = HttpClient.newBuilder()
        .connectTimeout(Duration.ofSeconds(30))
        .build();

    Path file = Path.of("/Users/valeriocetorelli/IdeaProjects/wrapidity-service-groot/src/test/java/input.csv");

    try (var lines = Files.lines(file)) {
      lines.filter(line -> !line.isBlank())
          .forEach(line -> {
            try {
              // Parse CSV: extract the last quoted JSON column
              String payload = extractJsonPayload(line);

              HttpRequest request = HttpRequest.newBuilder()
                  .uri(URI.create(ENDPOINT))
                  .header("accept", "application/json")
                  .header("Content-Type", "application/json")
                  .POST(HttpRequest.BodyPublishers.ofString(payload))
                  .build();

              HttpResponse<String> response =
                  client.send(request, HttpResponse.BodyHandlers.ofString());

              System.out.printf(
                  "Status=%d Response=%s%n",
                  response.statusCode(),
                  response.body());

              Thread.sleep(200);

            } catch (IOException | InterruptedException e) {
              throw new RuntimeException(e);
            }
          });
    }
  }

